import React from "react";
import {Box, Card, Grid, Paper } from "@material-ui/core";

class Work extends React.Component {
  render() {
    return (
      <Grid item>
      <Box height="95vh" border={1} id="work">
        <Box height="100%">
        <Grid>
          <Card>sdf</Card>
          </Grid>
        </Box>
      </Box>
      </Grid>
    );
  }
}
export default Work;
